INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$Is VidIQ free to use?$q$, $q$Yes, VidIQ offers a free plan with limited AI credits and core keyword and trend research tools; paid plans unlock more AI usage and advanced features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$How much does VidIQ Max cost?$q$, $q$VidIQ Max costs $39 per month billed monthly, or about $16.58 per month when billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$Who founded VidIQ?$q$, $q$VidIQ was founded in 2011 by Rob Sandie and Todd Troxell.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$Where is VidIQ headquartered?$q$, $q$VidIQ is headquartered in San Francisco, California, having originally started in Bethlehem, Pennsylvania.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$What is VidIQ's AI Coach?$q$, $q$AI Coach is a conversational assistant within VidIQ that answers questions about channel strategy, video performance, and growth tactics.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$Does VidIQ have an Enterprise plan?$q$, $q$Yes, VidIQ offers a custom-priced Enterprise plan for brands, agencies, and multi-channel networks managing multiple YouTube channels.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$Is VidIQ similar to TubeBuddy?$q$, $q$Yes, VidIQ and TubeBuddy are the two best-known third-party browser extension tools for YouTube SEO and channel optimization.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$Does VidIQ work on mobile?$q$, $q$Yes, VidIQ offers mobile apps for iOS and Android in addition to its browser extension and web dashboard.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$YouTube keyword research$q$, $q$Finding high-opportunity keywords and search terms before publishing a video.$q$, $q$YouTube creators and content strategists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$Channel growth coaching$q$, $q$Using AI Coach and analytics to identify what content and formats drive subscriber growth.$q$, $q$Growing and mid-size creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$Multi-channel agency management$q$, $q$Managing SEO and reporting across many client or brand YouTube channels from one account.$q$, $q$Agencies and multi-channel networks$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["150 AI credits monthly","Niche trends","Content ideas","Basic growth tips"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$Boost$q$, $q$Contact for current pricing$q$, $q$monthly or annual$q$, NULL, $q$["2,000 AI credits monthly","Thumbnail generation","Unlimited trends research","Subscriber insights","AI Coach access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$Max$q$, $q$$39/month (about $16.58/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["6,000 AI credits monthly","Expanded AI Coach conversations","Max Mode AI","Up to 11 hours of short clipping"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Multiple channel access","Team roles and permissions","Priority onboarding and support","Cross-channel insights and reporting"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$overview$q$, $q$What Is VidIQ$q$, 2, ARRAY[$q$VidIQ is a YouTube-focused growth and optimization platform that gives creators data and AI-driven suggestions to help videos perform better in search and recommendations. It is delivered through a browser extension, web dashboard, and mobile apps.$q$, $q$Founded in 2011 by Rob Sandie and Todd Troxell, VidIQ started as a Chrome extension providing analytics overlays directly on YouTube and has since grown into a broader suite covering keyword research, trend discovery, competitor tracking, and AI content generation for titles, descriptions, tags, and thumbnails.$q$, $q$The company relocated its headquarters to San Francisco and now serves millions of creators worldwide, positioning itself alongside tools like TubeBuddy as one of the leading third-party platforms built specifically for the YouTube creator ecosystem.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$VidIQ's browser extension overlays real-time keyword scores, competitor tags, and video statistics directly on YouTube pages, while its dashboard provides deeper trend research and channel audits.$q$, $q$AI features generate title, description, and tag suggestions, create thumbnail concepts, and power an AI Coach that answers creator questions about growth strategy and channel performance.$q$, $q$The platform also includes subscriber and audience insight tools, competitive channel tracking, and short-form clipping tools for turning long videos into shorts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23610ab0-1a86-4d06-82b8-503bd3931d89', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$VidIQ offers a free plan with limited monthly AI credits and basic trend research. Paid tiers include a Boost plan for growing creators and a Max plan priced at $39 per month billed monthly, or roughly $16.58 per month when billed annually, which unlocks more AI credits, expanded AI Coach access, and clipping tools.$q$, $q$An Enterprise plan with custom pricing is available for brands, agencies, and multi-channel networks that need team permissions, priority support, and cross-channel reporting.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$AI avatars$q$, $q$Over 1,900 realistic digital avatars with natural gestures and expressions for presenter-style videos.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$AI voice generation and cloning$q$, $q$More than 2,000 AI voices across 140-plus languages, plus custom voice cloning.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Video translation with lip-sync$q$, $q$Translates existing videos into other languages while syncing the speaker's lip movements.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Text-to-video and image-to-video$q$, $q$Converts scripts or static images into produced video content automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Template library$q$, $q$Over 2,800 pre-designed templates for marketing, education, and social media videos.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$AI image generation and editing$q$, $q$Generates and edits images, including background removal, alongside the video toolset.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Video dubbing and script generation$q$, $q$Tools to dub existing content and auto-generate scripts for new videos.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Music video generator$q$, $q$Creates music-synced videos from AI-generated or uploaded audio tracks.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Generous free tier with daily credits for casual use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Very large avatar, voice, and template library$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Broad multilingual support for voices and translation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Covers many video and image tasks in a single platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Budget-friendly compared to enterprise AI video tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Free tier videos are capped in length and resolution with a watermark$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Pricing structure spans many sub-tools, which can be confusing to compare$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$AI avatar realism can vary by avatar compared to top-tier competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Best higher-end features gated behind Business-level plans$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Is Vidnoz free to use?$q$, $q$Yes, Vidnoz offers a free plan with daily AI credits, though videos are limited in length, capped at lower resolution, and carry a watermark.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$How much does Vidnoz cost?$q$, $q$Paid plans typically start around $14.99 to $19.99 per month when billed annually, depending on the specific tool and tier chosen.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$When was Vidnoz founded?$q$, $q$Vidnoz was founded in 2016 and is headquartered in Los Angeles, United States.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$How many AI avatars does Vidnoz offer?$q$, $q$Vidnoz offers more than 1,900 AI avatars along with over 2,000 AI voices across 140-plus languages.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Can Vidnoz translate videos into other languages?$q$, $q$Yes, Vidnoz includes a video translation feature with automatic lip-syncing for localizing existing videos.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Does Vidnoz support voice cloning?$q$, $q$Yes, Vidnoz offers AI voice cloning to replicate a user's own voice for narration.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Who is Vidnoz best suited for?$q$, $q$Vidnoz is aimed at marketers, educators, sales teams, and individual creators who need quick, low-cost AI-generated video content.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Is Vidnoz secure and compliant?$q$, $q$Vidnoz states it maintains ISO/IEC 27001:2022 compliance and publishes a transparent privacy policy.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Marketing video production$q$, $q$Creating promotional and explainer videos quickly using AI avatars and templates.$q$, $q$Marketing teams and small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Multilingual training content$q$, $q$Translating and dubbing training or educational videos into multiple languages.$q$, $q$Educators and corporate L&D teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Sales and outreach videos$q$, $q$Generating personalized AI avatar videos for sales outreach and customer communication.$q$, $q$Sales and customer success teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Daily AI credits","Limited video length","720p export","Watermarked output"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Starter$q$, $q$About $14.99-$19.99/month (billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["1080p export","More monthly credits","No watermark"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$Business$q$, $q$Contact for pricing$q$, $q$monthly or annual$q$, NULL, $q$["Voice cloning at scale","Team collaboration","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$overview$q$, $q$What Is Vidnoz$q$, 2, ARRAY[$q$Vidnoz is an AI video creation platform that combines AI avatars, voice generation, and templated editing tools to let users produce videos quickly without filming or professional editing skills. It targets marketers, educators, HR and sales teams, and individual creators.$q$, $q$Founded in 2016 and based in Los Angeles, the company has built out a large catalog of over 1,900 AI avatars and 2,000-plus AI voices covering more than 140 languages, positioning itself as an accessible, budget-friendly alternative to enterprise AI video tools.$q$, $q$Vidnoz's product suite spans multiple specialized tools, including an AI avatar video generator, a video translator with lip-sync, an AI image generator, and background removal and photo editing utilities, all accessible from a unified account.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include AI avatars with natural gestures, text-to-speech and voice cloning, image-to-video conversion, and thousands of customizable video templates.$q$, $q$Video translation with automatic lip-syncing lets users localize existing videos into other languages, while AI image generation and editing tools extend the platform beyond video into static content creation.$q$, $q$Vidnoz also supports music video generation, video dubbing, and script generation, aiming to cover most steps of the video production workflow in one platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2dbc4826-ac2f-4e63-b546-bdd1459a0b34', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Vidnoz offers a free plan with daily AI credits that supports short, watermarked videos at limited resolution. Paid plans start with a Starter tier priced roughly $14.99 to $19.99 per month when billed annually, which removes watermarks and enables 1080p exports with more monthly credits.$q$, $q$A Business plan adds features like voice cloning at scale and team collaboration; pricing for higher tiers and specific sub-tools (such as the video translator) varies and is listed on dedicated pricing pages on vidnoz.com.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Multiple project views$q$, $q$List, Kanban, Gantt, and table views of the same tasks for different planning styles.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Self-hosting option$q$, $q$Fully open-source AGPLv3 codebase that can be deployed on a user's own server.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Managed Cloud hosting$q$, $q$Paid, EU-hosted managed service for users who don't want to self-host.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Task sharing and assignment$q$, $q$Share projects and assign tasks to collaborators for team-based work.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Import from other tools$q$, $q$Built-in migration from Todoist, Trello, and Microsoft To Do.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Reminders and due dates$q$, $q$Task reminders and deadline tracking to keep work on schedule.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Unlimited lists and tasks$q$, $q$No artificial caps on the number of projects, tasks, or reminders on Cloud plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Cross-platform access$q$, $q$Web app plus mobile and desktop clients for accessing tasks anywhere.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Completely free and open source when self-hosted$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Full data ownership and privacy control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Multiple flexible views (list, Kanban, Gantt, table) in one app$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Affordable managed Cloud option for non-technical users$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Active open-source community and transparent development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Self-hosting requires technical setup and maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Smaller ecosystem of integrations compared to major commercial task managers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$UI and polish can lag behind well-funded competitors like Todoist$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Support relies mainly on community channels for self-hosted users$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Is Vikunja free?$q$, $q$Yes, Vikunja is free and open source when self-hosted. A paid Vikunja Cloud option is available for users who prefer managed hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$How much does Vikunja Cloud cost?$q$, $q$Vikunja Cloud starts at 4 euros per month for the Personal plan, with Family and Organization plans priced at 10 euros per month and 5 euros per user per month respectively.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Can I migrate from Todoist or Trello to Vikunja?$q$, $q$Yes, Vikunja includes built-in migration tools to import tasks and projects from Todoist, Trello, and Microsoft To Do.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Is Vikunja open source?$q$, $q$Yes, Vikunja is licensed under AGPLv3 and its full source code is publicly available.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$When did Vikunja start?$q$, $q$Vikunja's development began with a first commit in June 2018.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$What views does Vikunja support?$q$, $q$Vikunja supports list, Kanban, Gantt chart, and table views of your tasks and projects.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Can teams use Vikunja together?$q$, $q$Yes, Vikunja supports project sharing and task assignment for team collaboration.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Where is Vikunja Cloud hosted?$q$, $q$Vikunja Cloud is made and hosted in the European Union.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Personal task management$q$, $q$Organizing personal to-do lists and reminders with full control over the data.$q$, $q$Individuals and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Self-hosted team project tracking$q$, $q$Running a private, self-hosted task and project management system for a team.$q$, $q$Privacy-focused small businesses and IT teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Open-source tool migration$q$, $q$Replacing proprietary task managers like Todoist or Trello with an open alternative.$q$, $q$Self-hosting enthusiasts and open-source advocates$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Self-Hosted$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full open-source app","Unlimited users and projects","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Cloud Personal$q$, $q$4 euros/month (40 euros/year)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited lists and tasks","10GB attachment storage","Email and community support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Cloud Family$q$, $q$10 euros/month$q$, $q$monthly or annual$q$, NULL, $q$["Up to 5 users","Shared household projects","All Personal plan features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$Cloud Organization$q$, $q$5 euros/user/month$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited teams","Centralized billing","50GB attachment storage","Priority email support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$overview$q$, $q$What Is Vikunja$q$, 2, ARRAY[$q$Vikunja is an open-source to-do list and project management application designed to give users complete ownership over their task data, either by self-hosting the software themselves or subscribing to the official managed Cloud service.$q$, $q$Development began with a first commit in June 2018, created because the founder found no existing open-source tool that met their needs for a privacy-respecting, self-hostable task manager. The project has since grown into a mature application supporting personal and team use.$q$, $q$Vikunja includes migration tools for users switching from Todoist, Trello, and Microsoft To Do, making it straightforward to move existing task lists and projects into the platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The app supports four distinct views of the same underlying tasks: a simple list, a Kanban board, a Gantt chart for timeline planning, and a table view for spreadsheet-style organization.$q$, $q$Users can share projects, assign tasks to teammates, set due dates and reminders, and collaborate without needing to switch to a separate tool for team coordination.$q$, $q$Because the entire codebase is open source under AGPLv3, users and organizations can audit the code, self-host it on their own infrastructure, and even modify it to fit specific needs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Vikunja is completely free when self-hosted, since the software is open source. For users who want managed hosting, Vikunja Cloud offers a Personal plan at 4 euros per month, a Family plan at 10 euros per month for up to five users, and an Organization plan at 5 euros per user per month with more storage and priority support.$q$, $q$All Vikunja Cloud plans include a 14-day free trial, and the company describes itself as bootstrapped and EU-hosted, without outside venture capital influencing its roadmap.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9d064484-1e39-4835-a77c-89f6fd35cc99', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
