INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$Automatic recording and analytics$q$, $q$Records events for on-demand replay and tracks real-time audience behavior.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$High production-quality live streaming compared to many webinar-only tools$q$, 0);
