INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$What is Vimeo Events?$q$, $q$Vimeo Events is Vimeo's product for hosting virtual and hybrid live streams, webinars, and online conferences with engagement and lead-capture tools.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$How much does Vimeo Events cost?$q$, $q$The Advanced plan starts at $75 per month when billed annually, covering 10 seats and 7TB of storage; Enterprise pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$When did Vimeo launch its Events product?$q$, $q$Vimeo launched Vimeo Events in November 2021.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$Who owns Vimeo?$q$, $q$Vimeo was taken private by Bending Spoons in a deal announced in September 2025 and finalized in November 2025, after being a standalone public company since May 2021.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$Does Vimeo Events support pre-recorded content?$q$, $q$Yes, Vimeo Events supports simulive broadcasting, which schedules pre-recorded video to play as if it were a live event.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$Does Vimeo Events integrate with CRM tools?$q$, $q$Yes, it integrates with HubSpot and Salesforce for lead capture during and after events.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$Can Vimeo Events run continuous broadcasts?$q$, $q$Yes, it supports 24/7 always-on channels with automated scheduling.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$Who is Vimeo Events built for?$q$, $q$It is built for marketers, educators, and enterprises running webinars, product launches, and virtual or hybrid conferences.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$Corporate webinars$q$, $q$Hosting branded, interactive webinars with registration and CRM lead capture.$q$, $q$B2B marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$Virtual conferences$q$, $q$Running multi-session virtual or hybrid conferences with live and simulive content.$q$, $q$Event organizers and associations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$Always-on broadcast channels$q$, $q$Operating a continuous branded video channel for training or media distribution.$q$, $q$Enterprises and media organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$Advanced$q$, $q$$75/month$q$, $q$annual$q$, NULL, $q$["10 seats","7TB storage","Live streaming and simulive","Webinar registration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Dedicated support","SSO/SCIM authentication","Advanced security and controls"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$overview$q$, $q$What Is Vimeo Events$q$, 2, ARRAY[$q$Vimeo Events is a dedicated virtual and hybrid events product from Vimeo, Inc., designed for organizations that need to run livestreams, webinars, and online conferences with production-quality broadcasting tools.$q$, $q$Vimeo, the parent platform, was founded in 2004 by Jake Lodwick and Zach Klein as a video-sharing project within CollegeHumor and is headquartered in New York City. The Events product launched in November 2021, building on video and live-streaming technology Vimeo had accumulated through earlier acquisitions such as Livestream in 2017.$q$, $q$Vimeo Events extends the core Vimeo hosting platform with tools specifically for scheduled, interactive broadcasts, positioning it as a video-quality-focused alternative to standalone webinar platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Vimeo Events supports 4K live streaming with multi-camera switching, simulive broadcasting of pre-recorded content, and 24/7 always-on channels with automated scheduling, plus custom branding through logos, lower thirds, and graphic overlays.$q$, $q$Audience engagement tools include live polls, chat, and Q&A, along with a webinar registration system that sends automated confirmations and reminders to attendees.$q$, $q$Events are automatically recorded for on-demand playback afterward, and the platform can multi-stream to social channels while integrating with CRM tools like HubSpot and Salesforce for lead capture and follow-up.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d990b19-e999-4c82-8ee9-31191d38d1f7', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Vimeo Events' Advanced plan starts at $75 per month when billed annually, including 10 seats and 7TB of storage.$q$, $q$An Enterprise plan is available with custom pricing for larger organizations, adding dedicated support and SSO/SCIM authentication.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Single-binary deployment$q$, $q$Ships as one dependency-free Go binary, simplifying self-hosted setup.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Cookie-free tracking$q$, $q$Tracks visitors without cookies, avoiding the need for consent banners under most privacy laws.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Unlimited websites and events$q$, $q$No artificial limits on the number of sites or tracked events within one instance.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Automatic TLS$q$, $q$Built-in TLS certificate handling for secure deployments out of the box.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Custom event and goal tracking$q$, $q$Tracks custom events and conversion goals beyond basic pageviews.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Outbound link and download tracking$q$, $q$Automatically records outbound clicks and file downloads.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$404 error monitoring$q$, $q$Flags broken links and missing pages via 404 tracking.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Lightweight tracking script$q$, $q$Under 1KB script size to minimize impact on site performance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Completely free and open source$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$No cookies required, simplifying privacy compliance$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Very lightweight single-binary deployment$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Efficient roaring-bitmap storage engine for compact, fast analytics$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Full data ownership since everything is self-hosted$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$No official managed cloud hosting option available$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Requires technical skill to deploy and maintain$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Smaller community and ecosystem than Plausible or Umami$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Limited third-party documentation and integrations so far$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Is Vince free?$q$, $q$Yes, Vince is completely free and open source under the AGPL-3.0 license, with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Who created Vince?$q$, $q$Vince was created by developer Geofrey Ernest after several years researching efficient analytics storage using roaring bitmap indexing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Does Vince use cookies?$q$, $q$No, Vince tracks visitors without cookies, which helps sites comply with GDPR, CCPA, and PECR without a cookie banner.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Can I self-host Vince?$q$, $q$Yes, Vince is designed exclusively for self-hosting and ships as a single dependency-free binary.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Does Vince offer a managed cloud version?$q$, $q$No, as of current research Vince does not offer an official managed hosting service; it is self-hosted only.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$How does Vince compare to Plausible or Umami?$q$, $q$Vince offers similar privacy-friendly, cookie-free analytics but is built around a different, highly efficient storage engine and is exclusively self-hosted.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$What license does Vince use?$q$, $q$Vince is licensed under AGPL-3.0.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Does Vince support unlimited websites?$q$, $q$Yes, a single Vince instance can track unlimited websites and events.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Privacy-first website analytics$q$, $q$Tracking site traffic without cookies to simplify GDPR and CCPA compliance.$q$, $q$Privacy-conscious website owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Self-hosted infrastructure control$q$, $q$Running analytics entirely on owned infrastructure instead of a third-party SaaS.$q$, $q$Developers and self-hosting enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Lightweight analytics for multiple sites$q$, $q$Tracking many websites from a single low-resource analytics instance.$q$, $q$Agencies and indie developers managing several sites$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$Self-Hosted$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Unlimited websites and events","Cookie-free tracking","Custom events and goals","Single-binary deployment"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$overview$q$, $q$What Is Vince$q$, 2, ARRAY[$q$Vince is an open-source, self-hosted web analytics tool built as a lightweight, privacy-friendly alternative to Google Analytics. It was created by developer Geofrey Ernest, who spent about three years researching how to apply roaring bitmap indexing to analytics event storage before releasing the project.$q$, $q$The tool emerged publicly around late 2024, positioned against existing privacy-focused analytics tools like Plausible Analytics, with the creator citing manageability and efficiency gaps in existing options as the motivation for building Vince.$q$, $q$Vince ships as a single, dependency-free binary written in Go, making deployment simple for developers who want to run their own analytics infrastructure rather than relying on a third-party SaaS provider.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Vince tracks pageviews, custom events, goal conversions, outbound link clicks, file downloads, and 404 errors without using cookies, helping sites comply with GDPR, CCPA, and PECR without a cookie consent banner.$q$, $q$It supports unlimited websites and events within a single self-hosted instance, includes automatic TLS support, and uses a lightweight tracking script under 1KB in size to minimize impact on page load speed.$q$, $q$The underlying storage engine uses roaring bitmap indexing to keep the analytics data compact and fast to query, even at meaningful scale, within a single binary deployment.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Vince is completely free and open source under the AGPL-3.0 license. There is no official paid or managed hosting tier; users deploy and run Vince entirely on their own infrastructure at no licensing cost.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('be0219f7-7fe9-4a97-a60c-8c7f5f4a3bdf', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$AI Designer$q$, $q$Generates ready-to-use design layouts from text prompts using AI.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Template library$q$, $q$Thousands of templates across more than 50 content types, from presentations to infographics.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Data visualization$q$, $q$Interactive charts, graphs, and data widgets for turning statistics into visuals.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Brand Wizard$q$, $q$Automatically applies brand colors, fonts, and logos across new designs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Interactivity tools$q$, $q$Clickable hotspots, animations, and embeds for interactive presentations and documents.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Content calendar$q$, $q$Plans and schedules social media and content publishing from within Visme.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Real-time collaboration$q$, $q$Commenting and co-editing tools for teams working on shared designs.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Large asset library$q$, $q$Millions of stock photos, icons, videos, and 3D graphics available in-app.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Strong data visualization and interactive content features beyond basic design tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Generous free plan with unlimited projects$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Bootstrapped, profitable company with a long track record$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Brand Wizard simplifies consistent brand application across content$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Wide range of content types beyond just social graphics$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Free plan restricts access to premium templates and export formats$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Enterprise plan requires a 10-user minimum, less suited to very small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Learning curve for advanced interactivity and data visualization features$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Smaller template ecosystem than Canva's much larger user-generated marketplace$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Is Visme free to use?$q$, $q$Yes, Visme offers a free Basic plan with unlimited projects, though it has limited templates, assets, and export options.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$How much does Visme cost?$q$, $q$The Starter plan is about $12.25 per month billed annually, and the Pro plan is about $24.75 per month billed annually; Enterprise pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Who founded Visme?$q$, $q$Visme was founded by Payman Taei, who built it starting around 2012-2013 as a side project of his web design agency.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Is Visme a publicly funded or venture-backed company?$q$, $q$No, Visme is fully bootstrapped and has never raised outside venture capital funding.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Where is Visme headquartered?$q$, $q$Visme is headquartered in Rockville, Maryland, United States.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$How does Visme compare to Canva?$q$, $q$Visme offers deeper data visualization, interactivity, and brand management tools aimed at business reporting, while Canva is broader and more social-media-design focused.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Does Visme offer discounts for students and educators?$q$, $q$Yes, Visme offers a Student plan at $48 per year and an Educator plan at $96 per year.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Can teams collaborate in Visme?$q$, $q$Yes, Visme supports real-time collaboration with commenting and co-editing on shared projects.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Business presentations and reports$q$, $q$Creating branded presentations, reports, and proposals with data visualization built in.$q$, $q$Business teams and consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Infographics and data storytelling$q$, $q$Turning statistics and data into interactive infographics and charts.$q$, $q$Marketers and content teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Brand-consistent content at scale$q$, $q$Using the Brand Wizard to keep visual content on-brand across a growing content library.$q$, $q$Marketing and design teams in larger organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Basic$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Unlimited projects","Limited templates and assets","Regular support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Starter$q$, $q$$12.25/month ($147/year)$q$, $q$annual$q$, NULL, $q$["All premium assets","Full template access","JPG/PNG/PDF downloads","24/7 support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Pro$q$, $q$$24.75/month ($297/year)$q$, $q$annual$q$, NULL, $q$["PPTX/HTML5/video/GIF exports","Brand Kit","Analytics","Privacy controls","Most integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$Enterprise$q$, $q$Custom (minimum 10 users)$q$, $q$annual$q$, NULL, $q$["Custom sub-domain","Enhanced security","Project management tools","SSO and 2FA","Dedicated customer success manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$overview$q$, $q$What Is Visme$q$, 2, ARRAY[$q$Visme is an AI-powered content creation platform that helps business teams design and manage branded presentations, infographics, reports, proposals, and other visual content at scale.$q$, $q$The company was founded by Payman Taei, who started building Visme around 2012-2013 as a side project alongside his existing web design agency, reinvesting agency revenue into the product until it became profitable around 2015. Visme has remained fully bootstrapped, never raising outside venture capital.$q$, $q$Headquartered in Rockville, Maryland, Visme now serves more than 35 million users globally and generates roughly $15 million in annual recurring revenue with a lean team of fewer than 100 employees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Visme's AI Designer converts text prompts into ready-to-use design layouts, while its template library spans more than 50 content types, from presentations to social graphics to infographics.$q$, $q$The platform includes interactive data visualization with charts and graphs, a Brand Wizard for automatically applying brand colors, fonts, and logos across content, and interactivity features like clickable hotspots, animations, and embedded links.$q$, $q$Real-time collaboration tools let teams comment, review, and co-edit designs, and a content calendar helps plan and schedule social media posts alongside other visual content.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6661ffae-4b7b-4c87-9e11-ab1ba1fe67cc', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Visme offers a free Basic plan with unlimited projects but limited templates and assets. The Starter plan costs about $12.25 per month billed annually ($147/year), and the Pro plan costs about $24.75 per month billed annually ($297/year), adding video and PPTX exports, brand kits, and analytics.$q$, $q$An Enterprise plan with custom pricing (minimum 10 users) adds SSO, enhanced security, and a dedicated customer success manager, while discounted Student ($48/year) and Educator ($96/year) plans are also available.$q$]::text[], 2);
