-- в”Ђв”Ђ VidIQ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$VidIQ is an AI-powered YouTube growth platform that helps creators research keywords, optimize titles and thumbnails, track trends, and analyze channel performance.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$Spanish$q$, $q$Russian$q$, $q$Portuguese$q$, $q$Turkish$q$, $q$Vietnamese$q$]::text[],
  seo_title = COALESCE($q$VidIQ Review: Pricing, Features and Alternatives for YouTube$q$, seo_title),
  seo_meta_description = COALESCE($q$VidIQ is an AI-powered YouTube SEO and analytics tool for creators. See pricing plans, features, pros, cons, and how it compares to alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$VidIQ is an AI-powered YouTube channel growth and optimization platform founded in 2011 (as a Chrome extension analytics company) by Rob Sandie and Todd Troxell, originally based in Bethlehem, Pennsylvania, before relocating its headquarters to San Francisco, California. In its early history the company raised $800,000 from investors including Mark Cuban in 2013 and achieved official YouTube certification the same year. Today VidIQ serves millions of creators across more than 190 countries through a browser extension, mobile apps, and web dashboard that provide keyword research, competitor analysis, trend discovery, AI-generated title, tag, and thumbnail suggestions, and channel analytics. The product uses an AI-credit system across its paid tiers, offering a free plan with 150 monthly AI credits, a Boost plan aimed at growing creators, a Max plan at $39 per month (about $16.58/month billed annually) with 6,000 AI credits and expanded AI coaching and clipping tools, and a custom-priced Enterprise plan for brands, agencies, and multi-channel networks needing team roles and cross-channel reporting. VidIQ positions itself against competitors like TubeBuddy (a similar YouTube extension-based optimization tool) and native YouTube Studio analytics, differentiating through its AI Coach feature, trend prediction, and creator coaching services. The company also runs YouTube-focused educational content and a Top 100 channel tracker. With roughly 51-200 employees and a long operating history in the creator economy space, VidIQ is one of the more established third-party tools built specifically around YouTube's algorithm and creator monetization ecosystem, alongside video editing and thumbnail tools that address adjacent parts of a creator's workflow.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '23610ab0-1a86-4d06-82b8-503bd3931d89';

