-- в”Ђв”Ђ Vikunja в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Vikunja is a free, open-source, self-hostable to-do list and project management app offering list, Kanban, Gantt, and table views for individuals and teams.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Small independent/bootstrapped team$q$, company_size),
  headquarters = COALESCE($q$European Union$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$and 20+ additional community-translated languages$q$]::text[],
  seo_title = COALESCE($q$Vikunja Review: Open-Source To-Do App Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Vikunja is a free, open-source, self-hostable to-do and project management app. Compare features, pricing, and alternatives like Todoist and Trello.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Vikunja is an open-source, self-hostable to-do list and project management application whose first code commit dates to June 2018, created by a developer known as kolaente (Konrad). It was built to give users full ownership of their task data as a privacy-respecting alternative to proprietary task managers such as Todoist, Trello, and Microsoft To Do, and it includes built-in migration tools to import data directly from those platforms. Vikunja offers four ways to view work: list, Kanban board, Gantt chart, and table views, alongside features for sharing projects, assigning tasks, setting reminders, and organizing personal or team workloads. The software is licensed under AGPLv3 and can be self-hosted for free on a user's own server or infrastructure, giving full control over data. For users who prefer not to self-host, the company offers Vikunja Cloud, a paid managed hosting service described as 'made and hosted in the EU' and run as a bootstrapped business without external venture funding; Cloud plans include a Personal plan at 4 euros per month (or 40 euros per year) with 10GB of storage, a Family plan at 10 euros per month for up to five users, and an Organization plan at 5 euros per user per month with 50GB storage and priority support, all backed by a 14-day free trial. Vikunja is positioned in the growing category of open-source SaaS alternatives, similar in spirit to tools like Nextcloud Tasks, competing on transparency, data ownership, and lack of vendor lock-in rather than enterprise feature breadth, appealing especially to privacy-conscious individuals, small teams, and self-hosting enthusiasts.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9d064484-1e39-4835-a77c-89f6fd35cc99';

